import { Textarea } from "@shery-ui/components";

export default function TextareaDemo() {
  return <Textarea placeholder="Type something…" />;
}

import { Textarea, Label } from "@shery-ui/components";

export default function TextareaWithLabel() {
  return (
    <div className="flex flex-col gap-1.5 w-full max-w-sm">
      <Label htmlFor="bio">Bio</Label>
      <Textarea id="bio" placeholder="Tell us about yourself…" />
    </div>
  );
}

import { Textarea } from "@shery-ui/components";

export default function TextareaDisabled() {
  return <Textarea placeholder="This field is disabled" disabled />;
}

import { Textarea } from "@shery-ui/components";

export default function TextareaInvalid() {
  return (
    <div className="flex flex-col gap-1.5 w-full max-w-sm">
      <Textarea aria-invalid="true" defaultValue="Bad input value" />
      <p className="text-sm text-destructive">This field has an error.</p>
    </div>
  );
}

